import { USDollar, capFirstLetter, handleTooltip } from "../utils/util";
import {
  line,
  scaleLinear,
  axisLeft,
  scaleTime,
  timeParse,
  min,
  scaleOrdinal,
  axisBottom,
  axisRight,
  max,
  select
} from "d3"

interface data {
  "year": number
  "principle": number
  "interest": number
  "balance": number
}
const handleKformat = (d: number) => {
  let formated: string | number = d
  if ((d / 1000) >= 1) {
    formated = Math.floor(d / 1000) + "K";
  }
  return formated;
}
export default class StackedBarChart extends HTMLElement {
  static get observedAttributes() {
    return ['data'];
  }
  tooltip

  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        :host {
          font-family: var(--font-family);
          font-size: 14px;
          display: flex;
          width: 100%;
        }
        .title {
          font: 15px sans-serif;
        }
        .legend {
          font: 10px sans-serif;
        }
        .axis path,
        .axis line {
          fill: none;
          stroke: #000;
          shape-rendering: crispEdges;
        }
        
        .x.axis.path {
          display: none;
        }
        
        .line {
          fill: none;
          stroke: #77a4f0;
          stroke-width: 2px;
        } 
        .y.axis {
          fill: var(--text-tertiary);
        }
        .tick text {
          color: var(--text-tertiary);
        }
        .dot {
          fill: var(--background-primary);
          stroke: #4477CE;
          cursor: pointer;
        }
      </style>
      <div id="root"></div>
    `
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.tooltipInstance = handleTooltip(this)
    this.render()
    window.addEventListener("resize", e => {
      this.render()
    })
    this.addEventListener("mouseout", e => {
      this.tooltip.style.display = "none"
    })
  }
  disconnectedCallback() {
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }
  renderLine = ({ svg, line, data, xScale, yScale, parseDate }) => {
    svg.append("path")
      .datum(data)
      .attr("class", "line")
      .attr("d", line)

    svg.selectAll(".dot")
      .data(data)
      .enter()
      .append("circle")
      .attr("class", "dot")
      .attr("cx", d => xScale(parseDate(d.year)))
      .attr("cy", d => yScale(d.balance))
      .attr("r", 3)
      .on('mouseover', (e, d) => {
        e.target.style.strokeWidth = "3px"
        this.tooltip.style.display = "flex"
        select(this.tooltip)
          .transition()
          .duration(200)
          .style('opacity', 1)
        const year = this.tooltip.querySelector(".year")
        year.innerHTML = d.year
        const dot = this.tooltip.querySelector(".dot")
        dot.style.background = "blue";
        const text = this.tooltip.querySelector(".text")
        text.innerHTML = `Balance ${USDollar.format(Math.floor(d.balance))}`
      })
      .on('mouseout', (e) => {
        e.target.style.strokeWidth = "1px"
        select(this.tooltip).style('opacity', 0)
      })
      .on('mousemove', e => {
        select(this.tooltip)
          .style('left', (e.clientX + 10) + 'px')
          .style('top', (e.clientY + 10) + 'px')
      })
  }

  render = () => {
    const self = this
    const parent = this.closest("div")
    if (!parent) return
    if (!this.shadowRoot) return
    const { width: rectW } = parent.getBoundingClientRect()
    const root = this.shadowRoot.querySelector("#root")
    if (!root) return
    root.innerHTML = ""
    const margin = { top: 10, right: 20, bottom: 50, left: 40 };
    const width = rectW - margin.left - margin.right;
    const height = 400 - margin.top - margin.bottom;
    const barWith = 10

    const parseDate = timeParse("%Y");

    const x = scaleTime()
      .range([0, width - margin.left]);
    const y = scaleLinear()
      .range([height, margin.top]);
    const y1 = scaleLinear()
      .range([height, margin.top]);

    const color = scaleOrdinal()
      .range(["#4477CE", "#A084E8"]);

    // const center = scaleLinear()
    //   .range([0, width]);
    // const centerLine = axisTop(center).ticks(0);


    let data = this.getAttribute("data")
    if (data) data = JSON.parse(data)
    else return

    if (Array.isArray(data) && data?.length) {
      const xAxis = axisBottom(x).tickSize(0).offset(0).tickPadding(10).tickSizeOuter(0);
      const yAxisRight = axisRight(y).tickSize(0).tickPadding(-20).ticks(4).tickFormat(handleKformat);
      const yAxisLeftMax = max(data, d => d.balance)
      y1.domain([0, yAxisLeftMax]);
      const yAxisLeft = axisLeft(y1)
        .tickSize(0)
        .tickPadding(10)
        .ticks(2)
        .tickValues([0, yAxisLeftMax])
        .tickFormat(handleKformat);

      const keys = Object.keys(data[0]).filter(function (key) {
        if (key !== "year" && key !== "balance") return key;
      });

      data.forEach(function (d) {
        let y0_positive = 0;

        d.components = keys.map(key => {
          return { key: key, y1: y0_positive, y0: y0_positive += d[key], data: d[key], year: d.year };
        })
      })

      const y_min = min(data, d => d.principle > d.interest ? d.interest : d.principle);
      const y_max = max(data, d => d.principle + d.interest);

      const datestart = min(data, d => parseDate(d.year));
      const dateend = max(data, d => parseDate(d.year));

      x.domain([datestart, dateend]);
      y.domain([0, y_max * 1.5]);
      color.domain(keys);

      const principle = line()
        .x((d) => x(parseDate(d.year)))
        .y((d) => y1(d.balance));

      const svg = select(root).append("svg")
        .attr("width", width + margin.left + margin.right)
        .attr("height", height + margin.top + margin.bottom)
        .append("g")
        .attr("transform", "translate(" + margin.left + "," + margin.top + ")");

      svg.append("g")
        .attr("class", "x axis")
        .attr("transform", `translate(${barWith / 2}, ${height})`)
        .call(xAxis)
        .call(d => d.select(".domain").remove())

      svg.append("g")
        .attr("class", "y axis")
        .attr("transform", `translate(${width}, 0)`)
        .call(yAxisRight)
        .call(d => d.select(".domain").remove())

      svg.append("g")
        .attr("class", "y axis")
        .call(yAxisLeft)
        .call(d => d.select(".domain").remove())

      // svg.append("g")
      //   .attr("class", "centerline")
      //   .attr("transform", `translate(0, ${y(0)})`)
      //   .call(centerLine);

      const entry = svg.selectAll(".entry")
        .data(data)
        .enter().append("g")
        .attr("class", "g")
        .attr("transform", d => "translate(" + x(parseDate(d.year)) + ", 0)")

      entry.selectAll("rect")
        .data(d => d.components)
        .enter().append("rect")
        .attr("width", barWith)
        .attr("y", d => y(d.y0))
        .attr("height", d => Math.abs(y(d.y0) - y(d.y1)))
        .style("opacity", "0.8")
        .style('cursor', "pointer")
        .style("fill", d => color(d.key))
        .on('mouseover', (e, d) => {
          e.target.style.opacity = 1
          this.tooltipInstance.show()
          const year = this.tooltip.querySelector(".year")
          year.innerHTML = d.year
          const dot = this.tooltip.querySelector(".dot")
          dot.style.background = color(d.key)
          const text = this.tooltip.querySelector(".text")
          text.innerHTML = `${d.key} ${USDollar.format(Math.floor(d.data))}`
        })
        .on('mouseout', (e) => {
          e.target.style.opacity = .8
          this.tooltipInstance.hide(e)
        })
        .on('mousemove', this.tooltipInstance.move)

      this.renderLine({ svg, line: principle, data, xScale: x, yScale: y1, parseDate })

      const legend = svg.selectAll(".legend")
        .data(color.domain())
        .enter().append("g")
        .attr("class", "legend")

      legend.append("rect")
        .attr("x", (d, i) => i * 80)
        .attr("y", height + margin.bottom - 15)
        .attr("width", 18)
        .attr("height", 8)
        .style("fill", color);

      legend.append("text")
        .attr("x", (d, i) => i * 80 + 24)
        .attr("y", height + margin.bottom - 11)
        .attr("dy", ".35em")
        .style("text-anchor", "start")
        .style("fill", "var(--text-tertiary)")
        .text((d) => {
          return capFirstLetter(d)
        });
    }


  }
}

